package com.knoxhack.echostationfall.world;
import com.knoxhack.echostationfall.EchoStationfall; import net.minecraft.core.registries.Registries; import net.minecraft.resources.*; import net.minecraft.server.MinecraftServer; import net.minecraft.server.level.ServerLevel; import net.minecraft.world.level.Level;
public final class StationfallDimensions { public static final ResourceKey<Level> STATIONFALL_STATION=ResourceKey.create(Registries.DIMENSION, Identifier.fromNamespaceAndPath(EchoStationfall.MODID,"stationfall_station")); private StationfallDimensions(){} public static boolean isStation(Level l){return l!=null&&l.dimension()==STATIONFALL_STATION;} public static ServerLevel resolve(MinecraftServer s, ServerLevel fallback){ServerLevel l=s.getLevel(STATIONFALL_STATION); return l!=null?l:fallback;} }
